	@Test
	void serviceRedirectsRejectsBadPathsAndDelegatesToRepositoryServlets() throws Exception {
		RepositoryManager manager = mock(RepositoryManager.class);
		Repository repository = mock(Repository.class);
		RepositoryInfo info = new RepositoryInfo();
		when(manager.getRepository("repo")).thenReturn(repository);
		when(manager.getRepositoryInfo("repo")).thenReturn(info);

		TestWorkbenchServlet servlet = initServlet(manager);

		CapturedResponse nullPathResponse = new CapturedResponse();
		servlet.service(request("/workbench", null), nullPathResponse);
		assertThat(nullPathResponse.getRedirect()).isEqualTo("/workbench/repositories");

		CapturedResponse rootResponse = new CapturedResponse();
		servlet.service(request("/workbench/", "/"), rootResponse);
		assertThat(rootResponse.getRedirect()).isEqualTo("/workbench/repositories");

		assertThatThrownBy(() -> servlet.service(request("/workbench", "repo"), new CapturedResponse()))
				.isInstanceOf(BadRequestException.class)
				.hasMessageContaining("Request path must contain a repository ID");

		RecordingProxyRepositoryServlet created = new RecordingProxyRepositoryServlet();
		servlet.createdServlets.add(created);
		servlet.service(request("/workbench/repo/summary", "/repo/summary"), new CapturedResponse());

		assertThat(created.initCount).isEqualTo(1);
		assertThat(created.serviceCount).isEqualTo(1);
		assertThat(created.lastServletPath).isEqualTo("/repo");
		assertThat(created.lastPathInfo).isEqualTo("/summary");
		assertThat(created.assignedRepository).isSameAs(repository);
		assertThat(created.assignedInfo).isSameAs(info);
		assertThat(created.assignedManager).isSameAs(manager);

		servlet.resetCache();
		assertThat(created.resetCount).isEqualTo(1);

		servlet.service(request("/workbench/repo/summary", "/repo/summary"), new CapturedResponse());
		assertThat(created.serviceCount).isEqualTo(2);

		servlet.destroy();
		assertThat(created.destroyCount).isEqualTo(1);
		verify(manager).shutDown();
	}

	@Test
	void serviceHandlesRepositoryErrorsValidationAndUnauthorizedResponses() throws Exception {
		RepositoryManager manager = mock(RepositoryManager.class);
		TestWorkbenchServlet servlet = initServlet(manager);

		when(manager.getRepository("missing")).thenReturn(null);
		CapturedResponse missingResponse = new CapturedResponse();
		assertThatThrownBy(() -> servlet.service(request("/workbench/missing", "/missing"), missingResponse))
				.isInstanceOf(BadRequestException.class)
				.hasMessageContaining("No such repository: missing");
		assertThat(missingResponse.getHeaders()).containsEntry("Cache-Control", "no-cache, no-store");

		TestWorkbenchServlet noRepoServlet = initServlet(manager, "ghost");
		RecordingProxyRepositoryServlet ghostProxy = new RecordingProxyRepositoryServlet();
		noRepoServlet.createdServlets.add(ghostProxy);
		noRepoServlet.service(request("/workbench/ghost", "/ghost"), new CapturedResponse());
		assertThat(ghostProxy.serviceCount).isEqualTo(1);

		TestWorkbenchServlet unauthorizedServlet = initServlet(manager);
		RecordingProxyRepositoryServlet unauthorizedProxy = new RecordingProxyRepositoryServlet();
		unauthorizedProxy.toThrow = new UnauthorizedException("nope");
		unauthorizedServlet.createdServlets.add(unauthorizedProxy);
		when(manager.getRepository("repo")).thenReturn(mock(Repository.class));
		when(manager.getRepositoryInfo("repo")).thenReturn(new RepositoryInfo());
		CapturedResponse unauthorizedResponse = new CapturedResponse();
		unauthorizedServlet.service(request("/workbench/repo", "/repo"), unauthorizedResponse);
		assertThat(unauthorizedResponse.getBody()).contains("failed to authenticate").contains("server.xsl");

		TestWorkbenchServlet wrappedUnauthorizedServlet = initServlet(manager);
		RecordingProxyRepositoryServlet wrappedUnauthorizedProxy = new RecordingProxyRepositoryServlet();
		wrappedUnauthorizedProxy.toThrow = new ServletException(new UnauthorizedException("wrapped"));
		wrappedUnauthorizedServlet.createdServlets.add(wrappedUnauthorizedProxy);
		when(manager.getRepository("wrapped")).thenReturn(mock(Repository.class));
		when(manager.getRepositoryInfo("wrapped")).thenReturn(new RepositoryInfo());
		CapturedResponse wrappedUnauthorizedResponse = new CapturedResponse();
		wrappedUnauthorizedServlet.service(request("/workbench/wrapped", "/wrapped"), wrappedUnauthorizedResponse);
		assertThat(wrappedUnauthorizedResponse.getBody()).contains("failed to authenticate");

		TestWorkbenchServlet validationServlet = initServlet(manager);
		when(manager.getRepository("invalid"))
				.thenThrow(new RepositoryConfigException("invalid", new ValidationFailure()));
		CapturedResponse validationResponse = new CapturedResponse();
		validationServlet.service(request("/workbench/invalid", "/invalid"), validationResponse);
		assertThat(validationResponse.getStatusCode()).isEqualTo(HttpServletResponse.SC_CONFLICT);
		assertThat(validationResponse.getRecordedContentType()).isEqualTo("text/plain");
		assertThat(validationResponse.getBody()).contains("SHACL validation failed").contains("ValidationReport");

		TestWorkbenchServlet failingServlet = initServlet(manager);
		when(manager.getRepository("broken")).thenThrow(new RepositoryException("broken"));
		assertThatThrownBy(
				() -> failingServlet.service(request("/workbench/broken", "/broken"), new CapturedResponse()))
						.isInstanceOf(ServletException.class)
						.hasCauseInstanceOf(RepositoryException.class);
	}

