	private static class TestWorkbenchServlet extends WorkbenchServlet {
		protected RepositoryManager managerToReturn;
		private RuntimeException managerFailure;
		protected final Deque<RecordingProxyRepositoryServlet> createdServlets = new ArrayDeque<>();
		private CookieHandler cookieHandler = new FixedCookieHandler(null);

		@Override
		protected RepositoryManager createRepositoryManager(String param) throws IOException, RepositoryException {
			if (managerFailure instanceof RepositoryException) {
				throw (RepositoryException) managerFailure;
			}
			if (managerFailure instanceof RuntimeException) {
				throw managerFailure;
			}
			return managerToReturn;
		}

		@Override
		protected ProxyRepositoryServlet createProxyRepositoryServlet() {
			return createdServlets.removeFirst();
		}

		@Override
		protected CookieHandler createCookieHandler() {
			return cookieHandler;
		}
	}

