	private static final class RecordingProxyRepositoryServlet extends ProxyRepositoryServlet {
		private int initCount;
		private int serviceCount;
		private int destroyCount;
		private int resetCount;
		private String lastServletPath;
		private String lastPathInfo;
		private RepositoryManager assignedManager;
		private RepositoryInfo assignedInfo;
		private Repository assignedRepository;
		private Throwable toThrow;

		@Override
		public void setRepositoryManager(RepositoryManager manager) {
			assignedManager = manager;
		}

		@Override
		public void setRepositoryInfo(RepositoryInfo info) {
			assignedInfo = info;
		}

		@Override
		public void setRepository(Repository repository) {
			assignedRepository = repository;
		}

		@Override
		public void init(ServletConfig config) {
			initCount++;
		}

		@Override
		public void service(HttpServletRequest req, HttpServletResponse resp) throws ServletException {
			serviceCount++;
			lastServletPath = req.getServletPath();
			lastPathInfo = req.getPathInfo();
			if (toThrow != null) {
				if (toThrow instanceof ServletException) {
					throw (ServletException) toThrow;
				}
				if (toThrow instanceof RuntimeException) {
					throw (RuntimeException) toThrow;
				}
			}
		}

		@Override
		public void destroy() {
			destroyCount++;
		}

		@Override
		public void resetCache() {
			resetCount++;
		}
	}

	private static final class FixedCookieHandler extends CookieHandler {
		private final String value;

		private FixedCookieHandler(String value) {
			super((String) null);
			this.value = value;
		}

		@Override
		protected String getCookieNullIfEmpty(HttpServletRequest req, HttpServletResponse resp, String name) {
			return value;
		}
	}

	private static final class ValidationFailure extends RuntimeException implements ValidationException {
		private final Model model = new LinkedHashModel();

		private ValidationFailure() {
			model.add(SimpleValueFactory.getInstance().createIRI("urn:report"), RDF.TYPE, SHACL.VALIDATION_REPORT);
		}

		@Override
		public Model validationReportAsModel() {
			return model;
		}
	}
